import React from "react";
import { Link } from "react-router-dom";
import { FaUser } from "react-icons/fa";   // account icon
import "../index.css";

function Navbar() {
  return (
    <nav className="navbar">
      {/* Brand Name */}
      <div className="logo">ElectroStore</div>

      {/* Nav Links */}
      <ul className="nav-links">
        <li><Link to="/">Home</Link></li>
        <li><Link to="/shop">Shop</Link></li>
        <li><Link to="/about">About Us</Link></li>
        <li><Link to="/contact">Contact</Link></li>
        <li><Link to="/seller">Seller Dashboard</Link></li>
      </ul>

      {/* Search Bar */}
      <div className="search-bar">
        <input type="text" placeholder="Search products..." />
        <button>🔍</button>
      </div>

      <div className="account">
  <Link to="/login" className="account-link">
    <FaUser className="account-icon" />
    <span>Account</span>
  </Link>
  <ul className="account-dropdown">
    <li><Link to="/cart">Add to Cart</Link></li>
    <li><Link to="/orders">Orders</Link></li>
    <li className="logout"><Link to="/logout">Logout</Link></li>
  </ul>
</div>

    </nav>
  );
}

export default Navbar;
